mapper.select:
WITH RECURSIVE UpstreamLineage AS ( SELECT ale.id, ale.source_urn, ale.target_urn, -1 AS depth, ale.create_time, ale.update_time, ale.edge_prop FROM datafusion.asset_lineage_edge ale where
ale.target_urn = #{req.nodeUrn}
ale.target_urn like concat(#{req.nodeUrn},':%') Or ale.target_urn = #{req.nodeUrn}
UNION ALL SELECT ale.id, ale.source_urn, ale.target_urn, ul.depth - 1 AS depth, ale.create_time, ale.update_time, ale.edge_prop FROM datafusion.asset_lineage_edge ale INNER JOIN UpstreamLineage ul ON ale.target_urn = ul.source_urn where depth > -50
and depth > -#{req.depth}
), DownstreamLineage AS ( SELECT ale.id, ale.source_urn, ale.target_urn, 1 AS depth, ale.create_time, ale.update_time, ale.edge_prop FROM datafusion.asset_lineage_edge ale where
ale.source_urn = #{req.nodeUrn}
ale.source_urn like concat(#{req.nodeUrn},':%') or ale.source_urn = #{req.nodeUrn}
UNION ALL SELECT ale.id, ale.source_urn, ale.target_urn, dl.depth + 1 AS depth, ale.create_time, ale.update_time, ale.edge_prop FROM datafusion.asset_lineage_edge ale INNER JOIN DownstreamLineage dl ON ale.source_urn = dl.target_urn where depth < 50
and depth <= #{req.depth}
)
select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from UpstreamLineage order by depth,sourceUrn asc
select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from DownstreamLineage order by depth,sourceUrn asc
select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from UpstreamLineage union all select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from DownstreamLineage order by depth,sourceUrn asc

WITH RECURSIVE UpstreamLineage AS ( SELECT ale.id, ale.source_urn, ale.target_urn, -1 AS depth, ale.create_time, ale.update_time, ale.edge_prop FROM datafusion.asset_lineage_edge ale where
ale.target_urn = #{req.nodeUrn}
ale.target_urn like concat(#{req.nodeUrn},':%') Or ale.target_urn = #{req.nodeUrn}
), DownstreamLineage AS ( SELECT ale.id, ale.source_urn, ale.target_urn, 1 AS depth, ale.create_time, ale.update_time, ale.edge_prop FROM datafusion.asset_lineage_edge ale where
ale.source_urn = #{req.nodeUrn}
ale.source_urn like concat(#{req.nodeUrn},':%') or ale.source_urn = #{req.nodeUrn}
)
select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from UpstreamLineage where source_urn != target_urn order by depth,sourceUrn asc
select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from DownstreamLineage where source_urn != target_urn order by depth,sourceUrn asc
select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from UpstreamLineage where source_urn != target_urn union all select id,source_urn as sourceUrn,target_urn as targetUrn,depth,edge_prop from DownstreamLineage where source_urn != target_urn order by depth,sourceUrn asc
